export const formatCurrency = (amount: number, currency: string = 'USD'): string => {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency,
  }).format(amount);
};

export const calculateDiscount = (originalPrice: number, discountPercentage: number): number => {
  return originalPrice - (originalPrice * (discountPercentage / 100));
};

export const calculateTotalPrice = (items: { price: number; quantity: number; }[]): number => {
  return items.reduce((total, item) => total + (item.price * item.quantity), 0);
};

export const formatDate = (date: Date): string => {
  return new Intl.DateTimeFormat('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  }).format(date);
};

export const filterProducts = (products: any[], filters: { size?: string; brand?: string; color?: string; priceRange?: [number, number]; }): any[] => {
  return products.filter(product => {
    const matchesSize = filters.size ? product.size === filters.size : true;
    const matchesBrand = filters.brand ? product.brand === filters.brand : true;
    const matchesColor = filters.color ? product.color === filters.color : true;
    const matchesPrice = filters.priceRange ? (product.price >= filters.priceRange[0] && product.price <= filters.priceRange[1]) : true;
    return matchesSize && matchesBrand && matchesColor && matchesPrice;
  });
};

export const sortProducts = (products: any[], sortBy: 'price' | 'rating' | 'popularity'): any[] => {
  return products.sort((a, b) => {
    if (sortBy === 'price') {
      return a.price - b.price;
    } else if (sortBy === 'rating') {
      return b.rating - a.rating;
    } else if (sortBy === 'popularity') {
      return b.popularity - a.popularity;
    }
    return 0;
  });
};
